import { useState } from "react";
import {
  ChevronDown,
  ChevronRight,
  ExternalLink,
  FileText,
  Ticket,
  ArrowRightLeft,
  MessageSquare,
  Bot,
} from "lucide-react";
import { Badge } from "../ui/Badge.js";
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from "../ui/Card.js";
